const items = $input.all();
const results = [];

for (const item of items) {
  const binaryData = item.binary?.data;
  if (!binaryData) {
    throw new Error('No binary data found');
  }
  const base64String = Buffer.from(
    await this.helpers.getBinaryDataBuffer(item.index ?? 0, 'data')
  ).toString('base64');
  results.push({
    json: {
      base64Image: base64String,
      mimeType: binaryData.mimeType || 'image/jpeg',
      replyToken: $('When LINE Event Received').item.json.events[0].replyToken,
      lineUserId: $('When LINE Event Received').item.json.events[0].source.userId
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  let text = item.json.text || item.json.response || '';

  // Remove markdown code fences if present
  text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  let parsed;
  try {
    parsed = JSON.parse(text);
  } catch (e) {
    // Try to extract JSON from the response
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      parsed = JSON.parse(jsonMatch[0]);
    } else {
      throw new Error('Could not parse Gemini response as JSON: ' + text);
    }
  }

  results.push({
    json: {
      name: parsed.name || '',
      company: parsed.company || '',
      title: parsed.title || '',
      phone: parsed.phone || '',
      email: parsed.email || '',
      address: parsed.address || '',
      replyToken: $('Encode Image as Base64').item.json.replyToken,
      lineUserId: $('Encode Image as Base64').item.json.lineUserId
    }
  });
}

return results;

